def find_all(text, pattern):
    n = len(text)
    m = len(pattern)
    if m == 0:
        return []
    if m > n:
        return []
    # Boyer-Moore-Horspool: build bad character table
    bad_char = {}
    for i in range(m - 1):
        bad_char[pattern[i]] = m - 1 - i
    results = []
    i = 0
    while i <= n - m:
        j = m - 1
        while j >= 0 and text[i + j] == pattern[j]:
            j -= 1
        if j < 0:
            results.append(i)
            i += 1
        else:
            skip = bad_char.get(text[i + m - 1], m)
            i += skip
    return results

def find_all(text, pattern):
    n = len(text)
    m = len(pattern)
    if m == 0:
        return []
    if m > n:
        return []
    # Boyer-Moore-Horspool with optimized bad character table
    bad_char = [m] * 256
    for i in range(m - 1):
        bad_char[ord(pattern[i])] = m - 1 - i
    results = []
    results_append = results.append
    i = 0
    while i <= n - m:
        j = m - 1
        while j >= 0 and text[i + j] == pattern[j]:
            j -= 1
        if j < 0:
            results_append(i)
            i += 1
        else:
            i += bad_char[ord(text[i + m - 1])]
    return results
